    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events Overview",
            Slug = "events-overview",
            Summary = "What events are, the four event types, attendee management, RSVP workflow, and automatic reminders.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","meetings","training","safety"]""",
            ContentJson = """{"body":"## Events Overview\n\nUse Events to schedule and track company events — meetings, training sessions, safety briefings, and other gatherings. You'll find it under Admin > Events. It gives you one calendar for everything happening in your organization.\n\n### Event Types\n\nEvery event is one of four types:\n- **Meeting** — team meetings, project reviews, stand-ups, and one-on-ones.\n- **Training** — skills training, onboarding, and certification prep.\n- **Safety** — safety briefings, emergency drills, and compliance reviews.\n- **Other** — company socials, announcements, facility tours, or anything else.\n\nEach type shows its own icon in the events list, so you can spot the kind of event at a glance and filter by it.\n\n### Attendees and RSVP\n\nWhen you create or edit an event, you pick attendees from your active employees. Each one gets a notification inviting them. Every attendee has a status:\n- **Invited** — the starting status; no response yet\n- **Accepted** — the person confirmed they'll come\n- **Declined** — the person can't make it\n- **Attended** — confirms afterward that the person showed up (handy for compliance)\n\nThe events list shows how many people are invited to each event, so you can see the count at a glance.\n\n**A note on responding:** attendees can't accept or decline from the app yet. Each person's status shows on their profile as read-only, and there's no button to change it. For now the status is set for you behind the scenes, not by anyone clicking a button.\n\n### Required vs Optional Events\n\nYou can mark an event as Required. When you do:\n- The invitation stands out more strongly in each person's notifications\n- A yellow Required label appears next to the event in the list\n- Everyone can see attendance is mandatory (for example, safety briefings or compliance training)\n\nOptional events show as plain text in the list.\n\n### Automatic Reminders\n\nThe system sends each attendee a reminder about 30 minutes before an event starts. This helps people show up even if they missed the original invitation. Each reminder goes out only once.\n\n### Where Events Appear\n\n- **Admin > Events** — the main place to create, edit, filter, and cancel events\n- **Shop Floor Display** — upcoming events show in the shop floor's upcoming section, so production workers see what's scheduled\n- **Employee Profile** — each employee's profile has an Events tab listing the upcoming events they're invited to, with their status (Invited, Accepted, Declined, or Attended). It's view-only here — there's nothing to respond to.\n\n### Cancelling Events\n\nCancelling an event doesn't delete it. The event drops out of the list, but its record is kept, so the history stays intact.\n\n### When to Use Events\n\n- Scheduling a team meeting or project review\n- Organizing mandatory safety briefings or emergency drills\n- Planning training for new hires or skill-building\n- Tracking attendance for compliance (who attended which safety training)\n- Announcing company-wide gatherings or social events","sections":[]}"""
        });

