            ContentJson = """{"appRoute":"/admin/events","startButtonLabel":"Tour Events","steps":[{"element":"[data-testid='new-event-btn']","popover":{"title":"New Event Button","description":"Click here to create an event. You'll fill in the title, type, when it starts and ends, the location, a description, who to invite, and whether attendance is required. Everyone you invite gets a notification right away.","side":"bottom"}},{"element":".panel-header app-select","popover":{"title":"Type Filter","description":"Show only one kind of event — Meeting, Training, Safety, or Other. Pick a type to narrow the list, or choose All to see everything. The list updates as you choose.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Events List","description":"Shows your active events, earliest first. For each one you see its title, type, start and end times, location, how many people are invited, and whether it's required. Click a column heading to sort by it.","side":"top"}}]}"""
