        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events Field Reference",
            Slug = "events-field-reference",
            Summary = "Complete reference for every field, button, event type, attendee status, validation rule, and action in Events.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","reference"]""",
            ContentJson = """{"title":"Events Field Reference","groups":[{"heading":"Event Form Fields","items":[{"label":"Title (required)","value":"The event's name, up to 200 characters. It shows in the list, in notifications, and to attendees. For example: 'Weekly Safety Briefing', 'Q2 Project Review', or 'New Hire Orientation'."},{"label":"Event Type (required)","value":"Pick one: Meeting, Training, Safety, or Other. This sets the event's icon in the list and lets you filter by it. Starts on Meeting."},{"label":"Location","value":"Optional, up to 200 characters. Where the event happens, in person or online — for example 'Conference Room B', 'Shop Floor Bay 3', or 'Zoom link in description'."},{"label":"Start Date (required)","value":"Pick the date the event begins. Works together with the start time."},{"label":"Start Time (required)","value":"Type the time it begins, in 24-hour HH:MM. Starts at 09:00."},{"label":"End Date (required)","value":"Pick the date it ends. For a one-day event, use the same date as the start."},{"label":"End Time (required)","value":"Type the time it ends, in 24-hour HH:MM. It must be after the start. Starts at 10:00."},{"label":"Description","value":"Optional, up to 2000 characters. Add the agenda, prep instructions, or any extra details."},{"label":"Attendees","value":"Pick as many active employees as you like from the list (shown as Last, First). Everyone you pick gets an invitation notification when you save the event."},{"label":"Required Attendance","value":"An on/off switch. Turn it on to mark the event mandatory. The invitation stands out more in each person's notifications, and a yellow 'Required' label shows next to the event in the list."}]},{"heading":"Attendee Fields","items":[{"label":"User","value":"The employee invited to the event, shown as Last, First."},{"label":"Status","value":"Where the person stands: Invited (the start), Accepted, Declined, or Attended. It's read-only — there's no way to respond in the app yet. Each person's status shows on their profile, and you can't change it there."},{"label":"Responded At","value":"When the person last changed their status. Blank while they're still Invited. Can't be changed in the app today."}]},{"heading":"Event Types","items":[{"label":"Meeting","value":"Team meetings, project reviews, stand-ups, one-on-ones, and other working sessions."},{"label":"Training","value":"Skills training, onboarding, certification prep, and other learning sessions."},{"label":"Safety","value":"Safety briefings, emergency drills, compliance reviews, and hazard training."},{"label":"Other","value":"Company socials, announcements, facility tours, and anything the other types don't cover."}]},{"heading":"Attendee Statuses","items":[{"label":"Invited","value":"The starting status when you add someone to an event. Means they haven't responded yet."},{"label":"Accepted","value":"The person confirmed they'll attend."},{"label":"Declined","value":"The person said they can't attend."},{"label":"Attended","value":"Confirms afterward that the person showed up. Handy for compliance, such as proving who was at a safety training."}]},{"heading":"Buttons and Actions","items":[{"label":"New Event (primary button)","value":"Opens the form to create an event. Everything starts fresh — type Meeting, 09:00 to 10:00, not required."},{"label":"Save / Create Event","value":"Saves the event. It's greyed out until the form is filled in correctly, or while it's saving. When it's greyed out, click the warning triangle to its left to see what's missing. Saving sends notifications to everyone you invited."},{"label":"Cancel (in the form)","value":"Closes the form without saving your changes."},{"label":"Edit (row icon)","value":"The pencil on each row. Opens the event's form filled in with its current details, including who's invited."},{"label":"Cancel Event (row icon)","value":"The red X on each row. Asks you to confirm, then cancels the event. It drops out of the list, but its record is kept."},{"label":"Type Filter","value":"A menu above the list. Show only one type of event. Choose All, Meeting, Training, Safety, or Other."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required. Can't be empty. Up to 200 characters."},{"label":"Event Type","value":"Required. Must be Meeting, Training, Safety, or Other."},{"label":"Start Date","value":"Required. Must be a real date."},{"label":"Start Time","value":"Required. Use 24-hour HH:MM."},{"label":"End Date","value":"Required. Must be a real date."},{"label":"End Time","value":"Required. The end must come after the start."},{"label":"Description","value":"Optional. Up to 2000 characters."},{"label":"Location","value":"Optional. Up to 200 characters."},{"label":"Attendees","value":"Optional. Pick any number of active employees. Duplicates are dropped automatically."},{"label":"What the warning triangle shows","value":"When the form isn't ready, the Save button is greyed out. Click the warning triangle to its left to see exactly what needs fixing — for example 'Title is required' or 'Start Date is required'."}]},{"heading":"List Columns","items":[{"label":"Title","value":"The event name. Click to sort."},{"label":"Type","value":"The event's type, shown with its icon. You can sort or filter by it."},{"label":"Start","value":"When the event begins, shown as date and time. Click to sort."},{"label":"End","value":"When the event ends, shown as date and time. Click to sort."},{"label":"Location","value":"Where it happens, in person or online. Click to sort."},{"label":"Attendees","value":"How many people are invited. Click to sort."},{"label":"Required","value":"Shows a yellow 'Required' label for mandatory events, or a muted 'Optional' otherwise. Click to sort."},{"label":"Actions","value":"The edit (pencil) and cancel (X) buttons for each row."}]},{"heading":"Notifications and Reminders","items":[{"label":"Invitation","value":"Goes to each person you invite when you save the event. It names who invited them, the event title, and when it starts. Required events stand out more strongly than optional ones."},{"label":"Event Reminder","value":"Each attendee gets a reminder about 30 minutes before the event starts. It goes out only once."},{"label":"Cancellation","value":"When you cancel an event, it drops out of the list but its record is kept, and everyone invited is told it's off."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
