            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ev1","text":"You need to schedule a mandatory safety briefing for all shop floor workers next Tuesday. Where do you create this event?","options":[{"id":"a","text":"Dashboard > Calendar widget > click the date"},{"id":"b","text":"Admin > Events > click New Event, choose the Safety type, turn on Required Attendance","isCorrect":true},{"id":"c","text":"Time Tracking > create a new time entry with category 'Safety'"},{"id":"d","text":"Shop Floor Display > Upcoming section > Add Event"}],"explanation":"Events are created in Admin > Events. Click New Event, choose the Safety type, fill in the details, pick your attendees, and turn on Required Attendance. A yellow Required label appears in the list, and attendees get an invitation that stands out more strongly."},{"id":"ev2","text":"What are the four event types available in the system?","options":[{"id":"a","text":"Urgent, Standard, Optional, Recurring"},{"id":"b","text":"Meeting, Training, Safety, Other","isCorrect":true},{"id":"c","text":"Internal, External, Virtual, Hybrid"},{"id":"d","text":"Daily, Weekly, Monthly, Annual"}],"explanation":"The four event types are Meeting, Training, Safety, and Other. Each type has its own icon in the events list, so you can tell them apart at a glance."},{"id":"ev3","text":"An employee has been invited to an event but hasn't responded yet. What is their attendee status?","options":[{"id":"a","text":"Pending"},{"id":"b","text":"No Response"},{"id":"c","text":"Invited","isCorrect":true},{"id":"d","text":"Unconfirmed"}],"explanation":"The default status for a newly added attendee is Invited. It remains Invited until the employee responds. The four possible statuses are: Invited, Accepted, Declined, and Attended."},{"id":"ev4","text":"Among the four attendee statuses, which one is meant for post-event confirmation that a person was physically present (the status that matters for compliance tracking)?","options":[{"id":"a","text":"Accepted — they confirmed beforehand"},{"id":"b","text":"Attended — confirms physical presence after the event","isCorrect":true},{"id":"c","text":"Completed — marks the training as done"},{"id":"d","text":"Present — a checked-in status"}],"explanation":"The Attended status is specifically meant for post-event confirmation of physical presence, which is what compliance tracking needs — proving people actually showed up, not just that they accepted. Note that attendee statuses aren't set from a button in the app today; the four statuses are Invited, Accepted, Declined, and Attended."},{"id":"ev5","text":"How does the system remind attendees about upcoming events?","options":[{"id":"a","text":"An email is sent 1 hour before the event starts"},{"id":"b","text":"A push notification is sent to their mobile device"},{"id":"c","text":"The system sends a reminder notification about 30 minutes before the event starts","isCorrect":true},{"id":"d","text":"No automatic reminders — attendees must check the calendar themselves"}],"explanation":"The system automatically sends each attendee a reminder about 30 minutes before an event starts. Each reminder goes out only once, so no one gets the same reminder twice."},{"id":"ev6","text":"You want to cancel a scheduled event. What happens when you click the cancel (X) icon on an event row?","options":[{"id":"a","text":"The event record is permanently deleted from the database"},{"id":"b","text":"A confirmation window appears, and confirming cancels the event — it drops out of the list but the record is kept","isCorrect":true},{"id":"c","text":"The event is moved to an archive section at the bottom of the page"},{"id":"d","text":"All attendees are removed but the event stays visible in the list"}],"explanation":"Cancelling doesn't delete an event. A window asks 'Cancel Event?' and warns that attendees will be told. Once you confirm, the event drops out of the list, but its record is kept so the history stays intact."},{"id":"ev7","text":"What's the difference between a Required and an Optional event?","options":[{"id":"a","text":"Required events block the attendee's calendar; optional events don't"},{"id":"b","text":"Required events show a yellow Required label in the list, and their invitation stands out more strongly in each person's notifications","isCorrect":true},{"id":"c","text":"Required events can only be created by admins; optional events can be created by anyone"},{"id":"d","text":"There is no functional difference — it's just a label"}],"explanation":"When you mark an event Required, two things change: its invitation stands out more strongly in each person's notifications, and a yellow Required label appears next to the event in the list."},{"id":"ev8","text":"You're looking at the events table and want to see only Training events. How do you filter?","options":[{"id":"a","text":"Click the Training column header to sort by type"},{"id":"b","text":"Use the Type filter menu above the list and select Training","isCorrect":true},{"id":"c","text":"Type 'Training' in the search box"},{"id":"d","text":"Right-click the list and select Filter > Training"}],"explanation":"The Type filter menu above the events list lets you show only one kind of event. Pick Training to see just training events, and the list updates right away."},{"id":"ev9","text":"When creating an event, the Save button is greyed out and you click the warning triangle to its left. What does it show?","options":[{"id":"a","text":"A loading spinner indicating the save is in progress"},{"id":"b","text":"A message saying 'Form is not valid'"},{"id":"c","text":"A short list of exactly which fields still need attention (for example, 'Title is required' or 'Start Date is required')","isCorrect":true},{"id":"d","text":"Nothing — the button simply can't be clicked when greyed out"}],"explanation":"When the form isn't ready, the Save button is greyed out. Click the warning triangle to its left to see a short list of exactly which fields still need attention, so you know what to fix before saving."},{"id":"ev10","text":"Where else in the application do events appear besides the Admin > Events page?","options":[{"id":"a","text":"Only on Admin > Events — events are an admin-only feature"},{"id":"b","text":"On the Shop Floor Display's upcoming section and in each employee's Events tab in their profile","isCorrect":true},{"id":"c","text":"On the Dashboard calendar widget and the Kanban board sidebar"},{"id":"d","text":"In the Chat module as automated event announcements"}],"explanation":"Events appear in three places: Admin > Events (main management view), the Shop Floor Display (upcoming events section so production workers see what's scheduled), and the Employee Detail view (Events tab showing events each person is invited to or has attended)."},{"id":"ev11","text":"An employee opens their Employee Detail Events tab and wants to accept an event invitation. What can they do from that screen?","options":[{"id":"a","text":"Click an Accept button on the event row to set their RSVP to Accepted"},{"id":"b","text":"Nothing — the tab shows their status as read-only; there's no respond or accept button in the app today","isCorrect":true},{"id":"c","text":"Drag the event to an 'Accepted' column to confirm attendance"},{"id":"d","text":"Reply to the invitation notification, which updates their status"}],"explanation":"Responding isn't available in the app yet. The employee's Events tab shows their status (Invited, Accepted, Declined, or Attended) as read-only — there's no button to accept or decline from that screen for now."}]}"""
